# Connect to Elasticsearch
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def index_document(index_name, doc_id, document):
    """Index a single document into Elasticsearch."""
    try:
        response = es.index(index=index_name, id=doc_id, body=document)
        logger.info(f"Indexed document with ID {response['_id']}")
    except Exception as e:
        logger.error(f"Failed to index document: {e}")

def bulk_index_documents(index_name, documents):
    """Bulk index multiple documents into Elasticsearch."""
    try:
        actions = [
            {
                "_index": index_name,
                "_id": doc.get("id"),
                "_source": doc
            }
            for doc in documents
        ]
        response = helpers.bulk(es, actions)
        logger.info(f"Bulk indexed {response[0]} documents")
    except Exception as e:
        logger.error(f"Failed to bulk index documents: {e}")

def search_query(index_name, query):
    """Search for documents using a given query."""
    try:
        response = es.search(index=index_name, body=query)
        logger.info(f"Found {len(response['hits']['hits'])} documents")
        return response['hits']['hits']
    except Exception as e:
        logger.error(f"Failed to execute search query: {e}")
        return []

